package de.velospot.data.repository

import de.velospot.data.remote.api.OsrmApi
import de.velospot.domain.model.BikeRoute
import de.velospot.domain.model.RoutePoint
import de.velospot.domain.repository.RoutingRepository
import javax.inject.Inject

class RoutingRepositoryImpl @Inject constructor(
    private val osrmApi: OsrmApi
) : RoutingRepository {

    override suspend fun getBikeRoute(
        startLatitude: Double,
        startLongitude: Double,
        endLatitude: Double,
        endLongitude: Double
    ): BikeRoute {
        val url = buildString {
            append("https://router.project-osrm.org/route/v1/bicycle/")
            append(startLongitude)
            append(',')
            append(startLatitude)
            append(';')
            append(endLongitude)
            append(',')
            append(endLatitude)
            append("?overview=full&geometries=geojson&alternatives=false&steps=false")
        }

        val response = osrmApi.getBikeRoute(url)
        if (response.code != "Ok") {
            throw IllegalStateException("Routing failed: ${response.code}")
        }

        val bestRoute = response.routes.firstOrNull()
            ?: throw IllegalStateException("No bike route returned")

        val points = bestRoute.geometry.coordinates.mapNotNull { coordinate ->
            if (coordinate.size < 2) {
                null
            } else {
                RoutePoint(
                    latitude = coordinate[1],
                    longitude = coordinate[0]
                )
            }
        }

        if (points.isEmpty()) {
            throw IllegalStateException("Route geometry is empty")
        }

        return BikeRoute(
            points = points,
            distanceMeters = bestRoute.distance,
            durationSeconds = bestRoute.duration
        )
    }
}

package de.velospot.data.repository

import de.velospot.data.remote.api.OsrmApi
import de.velospot.domain.model.BikeRoute
import de.velospot.domain.model.EmptyRouteGeometryException
import de.velospot.domain.model.GeoCoordinate
import de.velospot.domain.model.NoRouteFoundException
import de.velospot.domain.model.RoutePoint
import de.velospot.domain.model.RoutingFailedException
import de.velospot.domain.repository.RoutingRepository
import javax.inject.Inject

class RoutingRepositoryImpl @Inject constructor(
    private val osrmApi: OsrmApi
) : RoutingRepository {

    override suspend fun getBikeRoute(from: GeoCoordinate, to: GeoCoordinate): BikeRoute {
        val url = buildString {
            append("https://router.project-osrm.org/route/v1/bicycle/")
            append(from.longitude)
            append(',')
            append(from.latitude)
            append(';')
            append(to.longitude)
            append(',')
            append(to.latitude)
            append("?overview=full&geometries=geojson&alternatives=false&steps=false")
        }

        val response = osrmApi.getBikeRoute(url)
        if (response.code != "Ok") {
            throw RoutingFailedException(response.code)
        }

        val bestRoute = response.routes.firstOrNull()
            ?: throw NoRouteFoundException()

        val points = bestRoute.geometry.coordinates.mapNotNull { coordinate ->
            if (coordinate.size < 2) {
                null
            } else {
                RoutePoint(
                    latitude = coordinate[1],
                    longitude = coordinate[0]
                )
            }
        }

        if (points.isEmpty()) {
            throw EmptyRouteGeometryException()
        }

        return BikeRoute(
            points = points,
            distanceMeters = bestRoute.distance,
            durationSeconds = bestRoute.duration
        )
    }
}

package de.velospot.domain.model

// ─── Typed domain errors ──────────────────────────────────────────────────────

/**
 * Represents all possible error states that can occur in the map feature.
 * Used in [de.velospot.feature.map.presentation.MapUiState] and
 * [de.velospot.feature.map.presentation.NavigationUiState] instead of raw strings.
 */
sealed class MapError {
    /** Network or server error while loading parking data. */
    data object NetworkUnavailable : MapError()

    /** GPS / location permission unavailable. */
    data object LocationUnavailable : MapError()

    /** Routing API returned a non-OK status code. */
    data class RoutingFailed(val code: String) : MapError()

    /** Routing API returned no routes for the given coordinates. */
    data object NoRouteFound : MapError()

    /** Route was returned but geometry contains no coordinates. */
    data object EmptyRouteGeometry : MapError()

    /** Catch-all for unexpected exceptions. */
    data class Unknown(val message: String?) : MapError()
}

// ─── Domain exceptions thrown by data-layer implementations ──────────────────

/** Thrown when the routing API returns a non-OK status code. */
class RoutingFailedException(val code: String) : Exception("Routing API returned: $code")

/** Thrown when the routing API returns no routes. */
class NoRouteFoundException : Exception("No route returned by routing API")

/** Thrown when a returned route contains no geometry coordinates. */
class EmptyRouteGeometryException : Exception("Route geometry is empty")

package de.velospot.domain.repository
import kotlinx.coroutines.flow.Flow
/** * Repository interface for managing location permissions and current user position. */ interface LocationRepository {
/** * Get current user location as a Flow. * Emits GeoPoint data when location updates are available. * * @return Flow of location coordinates (latitude, longitude) */ fun getCurrentLocationFlow(): Flow<Pair<Double, Double>?>
/** * Start listening to location updates. */ fun startLocationUpdates()
/** * Stop listening to location updates. */ fun stopLocationUpdates() }

package de.velospot.domain.repository
import de.velospot.domain.model.GeoCoordinate import kotlinx.coroutines.flow.Flow
/** * Repository interface for managing location permissions and current user position. */ interface LocationRepository {
/** * Get current user location as a Flow. * Emits a [GeoCoordinate] whenever a new location fix is available. * * @return Flow of [GeoCoordinate], or null if location is not yet known. */ fun getCurrentLocationFlow(): Flow<GeoCoordinate?>
/** * Start listening to location updates. */ fun startLocationUpdates()
/** * Stop listening to location updates. */ fun stopLocationUpdates() }

